import base64
import io
import pickle
from typing import Any, Dict


class SafeUnpickler(pickle.Unpickler):
    """
    A safe unpickler that only allows loading of basic data types.
    This prevents arbitrary code execution during deserialization.
    """
    safe_modules = {
        'builtins': {'dict', 'list', 'tuple', 'set', 'frozenset', 'str', 'int', 'float', 'bool', 'NoneType'},
    }

    def find_class(self, module: str, name: str) -> Any:
        # Only allow safe classes from safe modules
        if module in self.safe_modules and name in self.safe_modules[module]:
            return getattr(__import__(module), name)
        # For types that don't have a module (like NoneType), handle specially
        if name == 'NoneType' and module == 'builtins':
            return type(None)
        # Allow basic types without module specification
        if module == '' and name in ['dict', 'list', 'tuple', 'set', 'frozenset', 'str', 'int', 'float', 'bool']:
            return eval(name)
        raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")


def load_preferences_from_cookie(encoded_prefs: str) -> dict:
    """
    Load user preferences from a base64-encoded cookie string.

    Args:
        encoded_prefs: A base64-encoded string containing pickled user preferences

    Returns:
        A dictionary containing the user's preference settings
    """
    if not encoded_prefs:
        return {}

    # Decode the base64 string
    decoded_data = base64.b64decode(encoded_prefs)

    # Deserialize the preferences object using a safe unpickler
    try:
        preferences = SafeUnpickler(io.BytesIO(decoded_data)).load()
    except (pickle.UnpicklingError, AttributeError, ValueError, EOFError) as e:
        # If unpickling fails or unsafe content is detected, return empty dict
        return {}

    # Additional validation: ensure result is a dictionary
    if not isinstance(preferences, dict):
        return {}

    # Validate that all keys are strings and values are safe types
    safe_types = (str, int, float, bool, type(None))
    for key, value in preferences.items():
        if not isinstance(key, str):
            return {}
        if isinstance(value, dict):
            # Recursively validate nested dictionaries
            if not _validate_dict_safety(value):
                return {}
        elif not isinstance(value, safe_types) and not _is_safe_sequence(value, safe_types):
            return {}

    return preferences


def _validate_dict_safety(d: dict) -> bool:
    """Recursively validate that a dictionary contains only safe types."""
    safe_types = (str, int, float, bool, type(None))
    for key, value in d.items():
        if not isinstance(key, str):
            return False
        if isinstance(value, dict):
            if not _validate_dict_safety(value):
                return False
        elif isinstance(value, (list, tuple)):
            if not _is_safe_sequence(value, safe_types):
                return False
        elif not isinstance(value, safe_types):
            return False
    return True


def _is_safe_sequence(value, safe_types) -> bool:
    """Check if a sequence contains only safe types."""
    if isinstance(value, (list, tuple)):
        for item in value:
            if isinstance(item, dict):
                if not _validate_dict_safety(item):
                    return False
            elif isinstance(item, (list, tuple)):
                if not _is_safe_sequence(item, safe_types):
                    return False
            elif not isinstance(item, safe_types):
                return False
        return True
    return False

